#!/usr/bin/env bash
# Cover fetcher for the antilibrary. Run from the repo root on a machine with network:
#   bash tools/fetch_covers.sh
# Pulls cover art via the iTunes Search API (no key) into assets/covers/<slug>.jpg,
# named by entry slug so index.html picks it up automatically. Skips slugs that already
# have a cover; paced ~1/s to stay under iTunes rate limits. Misses are harmless —
# index.html auto-hides any cover whose file is absent. Regenerated by tools/gen_books.py.
set -uo pipefail
cd "$(dirname "$0")/.."
mkdir -p assets/covers
UA="antilibrary-cover-fetch/1.0 (github.com/christian93kg/antilibrary)"

fetch() { # <slug> <media: ebook|movie> <search term>
  local slug="$1" media="$2" term="$3" q url
  [ -s "assets/covers/${slug}.jpg" ] && { echo "  . ${slug} (have)"; return; }
  q="$(python3 -c 'import urllib.parse,sys; print(urllib.parse.quote(sys.argv[1]))' "$term")"
  if [ "$media" = "movie" ]; then
    # films: Wikipedia infobox poster (iTunes movie search is dead). generator=search
    # resolves title variants + year disambiguation; pilicense=any allows fair-use posters.
    url="$(curl -s --max-time 12 -A "$UA" "https://en.wikipedia.org/w/api.php?action=query&format=json&generator=search&gsrsearch=${q}&gsrlimit=1&prop=pageimages&piprop=original&pilicense=any" \
      | python3 -c 'import json,sys; p=json.load(sys.stdin).get("query",{}).get("pages",{}); v=(list(p.values())[0] if p else {}); print((v.get("original") or {}).get("source",""))' 2>/dev/null || true)"
  else
    # books: iTunes Search ebook artwork, upscaled 100->600.
    url="$(curl -s --max-time 10 "https://itunes.apple.com/search?term=${q}&media=${media}&limit=1" \
      | python3 -c 'import json,sys; r=json.load(sys.stdin).get("results",[]); print(r[0]["artworkUrl100"].replace("100x100bb","600x600bb") if r else "")' 2>/dev/null || true)"
  fi
  if [ -n "$url" ] && curl -sf --max-time 20 -A "$UA" -o "assets/covers/${slug}.jpg" "$url"; then
    echo "  + ${slug}"
  else
    echo "  - ${slug}"
  fi
  sleep 2
}

echo "Fetching covers..."

